import React, { useState, useEffect } from 'react';
import { problemService } from '../api/problemService';
import { 
  ChevronLeft, 
  Play, 
  Send, 
  Settings, 
  Info, 
  MessageSquare, 
  History,
  Terminal,
  Code
} from 'lucide-react';

const ProblemEditor = ({ problemId, onBack }) => {
  const [problem, setProblem] = useState(null);
  const [loading, setLoading] = useState(true);
  const [selectedLang, setSelectedLang] = useState('Java');
  const [code, setCode] = useState('');
  const [activeTab, setActiveTab] = useState('desc'); // desc, solution, sub
  const [output, setOutput] = useState(null);
  const [running, setRunning] = useState(false);

  useEffect(() => {
    fetchProblem();
  }, [problemId]);

  const fetchProblem = async () => {
    setLoading(true);
    try {
      const data = await problemService.getById(problemId);
      setProblem(data);
      setCode(data.starterCode[selectedLang] || '');
    } catch (err) {
      console.error('Failed to fetch problem', err);
    } finally {
      setLoading(false);
    }
  };

  const handleRun = () => {
    setRunning(true);
    setTimeout(() => {
      setOutput({ status: 'Accepted', runtime: '42ms', memory: '15.4MB', message: 'All test cases passed!' });
      setRunning(false);
    }, 1500);
  };

  const handleSubmit = async () => {
    setRunning(true);
    try {
      const res = await problemService.submit(problemId, { language: selectedLang, code });
      setOutput(res);
    } catch (err) {
      setOutput({ status: 'Error', message: 'Failed to submit code.' });
    } finally {
      setRunning(false);
    }
  };

  if (loading) return <div className="app-page on">Loading problem workspace...</div>;

  return (
    <div className="app-page on" style={{ padding: '0', display: 'flex', flexDirection: 'column' }}>
      {/* Editor Header */}
      <div className="app-topbar" style={{ background: 'var(--bg1)', borderBottom: '1px solid var(--b1)', height: '45px' }}>
        <button className="btn btn-ghost btn-sm" onClick={onBack} style={{ border: 'none' }}>
          <ChevronLeft size={16} />
          <span>Problem List</span>
        </button>
        <div className="tb-sep"></div>
        <div className="f12 fw6 tc">{problem.id}. {problem.title}</div>

        <div className="tb-right" style={{ gap: '12px' }}>
          <div className="input-wrap" style={{ width: '120px' }}>
            <select 
              value={selectedLang} 
              onChange={(e) => {
                setSelectedLang(e.target.value);
                setCode(problem.starterCode[e.target.value] || '');
              }}
              style={{ padding: '4px 12px', fontSize: '12px', background: 'var(--bg3)' }}
            >
              <option>Java</option>
              <option>Python</option>
              <option>C++</option>
              <option>JavaScript</option>
            </select>
          </div>
          <button className="btn btn-ghost btn-sm">
            <Settings size={14} />
          </button>
        </div>
      </div>

      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {/* Left Panel: Description */}
        <div style={{ width: '40%', borderRight: '1px solid var(--b1)', display: 'flex', flexDirection: 'column', background: 'var(--bg2)' }}>
          <div style={{ display: 'flex', borderBottom: '1px solid var(--b1)', background: 'var(--bg1)' }}>
            <button className={`edtab ${activeTab === 'desc' ? 'on' : ''}`} onClick={() => setActiveTab('desc')}>
              <Info size={14} style={{ marginRight: '6px' }} /> Description
            </button>
            <button className={`edtab ${activeTab === 'sol' ? 'on' : ''}`} onClick={() => setActiveTab('sol')}>
              <Code size={14} style={{ marginRight: '6px' }} /> Editorial
            </button>
            <button className={`edtab ${activeTab === 'sub' ? 'on' : ''}`} onClick={() => setActiveTab('sub')}>
              <History size={14} style={{ marginRight: '6px' }} /> Submissions
            </button>
          </div>
          <div style={{ flex: 1, overflowY: 'auto', padding: '20px' }}>
            <h2 className="section-title mb8">{problem.title}</h2>
            <div style={{ display: 'flex', gap: '8px', marginBottom: '20px' }}>
              <span className={`badge ${problem.difficulty === 'Easy' ? 'bg' : problem.difficulty === 'Medium' ? 'bm' : 'br'}`}>
                {problem.difficulty}
              </span>
              {problem.topics.map((t, i) => <span key={i} className="badge bdark">{t}</span>)}
            </div>

            <div className="f13 tc" style={{ lineHeight: '1.7' }} dangerouslySetInnerHTML={{ __html: problem.description }}></div>

            <div className="divider"></div>

            <div className="card" style={{ background: 'var(--bg1)', border: 'none' }}>
              <div className="f11 fw7 mb8 tc">TAGS</div>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px' }}>
                {problem.companies?.map((c, i) => <span key={i} className="badge bc">{c}</span>)}
              </div>
            </div>
          </div>
        </div>

        {/* Right Panel: Code Editor */}
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
          <div style={{ flex: 1, position: 'relative' }}>
            <textarea 
              value={code} 
              onChange={(e) => setCode(e.target.value)}
              style={{
                width: '100%',
                height: '100%',
                background: 'var(--bg0)',
                color: '#d4d4d4',
                fontFamily: 'var(--mono)',
                fontSize: '13px',
                padding: '20px',
                border: 'none',
                outline: 'none',
                resize: 'none'
              }}
              spellCheck="false"
            />
          </div>

          {/* Terminal / Output */}
          <div style={{ height: output ? '250px' : '45px', borderTop: '1px solid var(--b1)', display: 'flex', flexDirection: 'column', background: 'var(--bg2)' }}>
            <div style={{ height: '45px', display: 'flex', alignItems: 'center', padding: '0 16px', borderBottom: output ? '1px solid var(--b1)' : 'none' }}>
              <div className="f12 fw7 tc" style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                <Terminal size={14} /> Console
              </div>
              <div className="tb-right" style={{ gap: '8px' }}>
                <button 
                  className={`btn btn-ghost btn-sm ${running ? 'loading' : ''}`} 
                  onClick={handleRun}
                  disabled={running}
                >
                  <Play size={14} fill="currentColor" />
                  <span className="btn-txt">Run</span>
                  <div className="btn-spinner"></div>
                </button>
                <button 
                  className={`btn btn-primary btn-sm ${running ? 'loading' : ''}`}
                  onClick={handleSubmit}
                  disabled={running}
                >
                  <Send size={14} />
                  <span className="btn-txt">Submit</span>
                  <div className="btn-spinner"></div>
                </button>
              </div>
            </div>
            {output && (
              <div style={{ flex: 1, overflowY: 'auto', padding: '16px', fontFamily: 'var(--mono)', fontSize: '13px' }}>
                <div style={{ color: output.status === 'Accepted' ? 'var(--easy)' : 'var(--hard)', fontWeight: '700', fontSize: '18px', marginBottom: '8px' }}>
                  {output.status}
                </div>
                <div className="tc mb4">Runtime: <span className="t1c">{output.runtime || 'N/A'}</span></div>
                <div className="tc mb12">Memory Usage: <span className="t1c">{output.memory || 'N/A'}</span></div>
                <div style={{ background: 'var(--bg0)', padding: '12px', borderRadius: '6px', border: '1px solid var(--b1)', color: 'var(--t2)' }}>
                  {output.message}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProblemEditor;

import React from 'react';
import { NavLink } from 'react-router-dom';
import { 
  LayoutDashboard, 
  Code2, 
  BookOpen, 
  Calculator, 
  Map, 
  MessageSquare, 
  Briefcase, 
  Trophy, 
  GraduationCap, 
  Award,
  Users
} from 'lucide-react';

const Sidebar = () => {
  const menuItems = [
    { label: 'PREPARATION', type: 'label' },
    { icon: LayoutDashboard, label: 'Dashboard', path: '/dashboard' },
    { icon: Code2, label: 'Problems', path: '/problems' },
    { icon: BookOpen, label: 'Resume Builder', path: '/resume-builder' },
    { icon: Calculator, label: 'Aptitude Quiz', path: '/aptitude' },
    { icon: Map, label: 'Study Roadmap', path: '/roadmap' },

    { label: 'OPPORTUNITIES', type: 'label' },
    { icon: Briefcase, label: 'Jobs & Interns', path: '/jobs' },
    { icon: Trophy, label: 'Contests', path: '/contests' },

    { label: 'PLACEMENT PREP', type: 'label' },
    { icon: GraduationCap, label: 'Interview Exp', path: '/interviews' },
    { icon: Video, label: 'Mock Interviews', path: '/mock-interviews' },
    { icon: Award, label: 'Course Catalog', path: '/courses' },
    { icon: MessageSquare, label: 'AI Assistant', path: '/ai' },
    { icon: Users, label: 'Community', path: '/community' },
  ];

  return (
    <div className="app-sidebar">
      {menuItems.map((item, idx) => {
        if (item.type === 'label') {
          return <div key={idx} className="sb-lbl mt12">{item.label}</div>;
        }

        const Icon = item.icon;
        return (
          <NavLink 
            key={idx} 
            to={item.path} 
            className={({ isActive }) => `sb-item ${isActive ? 'on' : ''}`}
          >
            <Icon size={18} />
            <span>{item.label}</span>
          </NavLink>
        );
      })}
    </div>
  );
};

export default Sidebar;

