import React, { createContext, useContext, useState, useEffect } from 'react';
import { authService } from '../api/authService';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const savedUser = authService.getCurrentUser();
    if (savedUser) setUser(savedUser);
    setLoading(false);
  }, []);

  const login = async (credentials) => {
    const data = await authService.login(credentials);
    setUser(data);
    return data;
  };

  const register = async (userData) => {
    const data = await authService.register(userData);
    setUser(data);
    return data;
  };

  const logout = () => {
    authService.logout();
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, loading, login, register, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);

import React, { useState, useEffect } from 'react';
import { jobService } from '../api/jobService';
import { Search, Briefcase, MapPin, DollarSign, ExternalLink, Heart } from 'lucide-react';

const Jobs = () => {
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('');

  useEffect(() => {
    fetchJobs();
  }, [filter]);

  const fetchJobs = async () => {
    setLoading(true);
    try {
      const data = await jobService.getAll(filter);
      setJobs(data);
    } catch (err) {
      console.error('Failed to fetch jobs', err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app-page on">
      <div className="section-hdr">
        <div>
          <h1 className="section-title">Jobs & Internships</h1>
          <p className="section-sub">Curated openings for 2024, 2025, and 2026 graduates.</p>
        </div>
      </div>

      <div className="card mb24" style={{ padding: '12px' }}>
        <div style={{ display: 'flex', gap: '12px' }}>
          <div className="input-wrap" style={{ flex: 1 }}>
            <span className="input-ico"><Search size={14} /></span>
            <input type="text" placeholder="Search by role, company, or keywords..." style={{ paddingLeft: '38px' }} />
          </div>
          <div style={{ display: 'flex', gap: '6px' }}>
            {['All', 'FullTime', 'Internship', 'Remote'].map((f) => (
              <button 
                key={f}
                className={`btn btn-sm ${filter === (f === 'All' ? '' : f) ? 'btn-primary' : 'btn-ghost'}`}
                onClick={() => setFilter(f === 'All' ? '' : f)}
              >
                {f}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="g3">
        {loading ? (
          <div style={{ gridColumn: '1/-1', textAlign: 'center', padding: '40px', color: 'var(--t3)' }}>Loading jobs...</div>
        ) : (
          jobs.map((j) => (
            <div key={j.id} className="job-card">
              <div style={{ display: 'flex', justifyBetween: 'space-between', alignItems: 'flex-start' }}>
                <div className="job-logo">{j.logoEmoji}</div>
                {j.new && <span className="badge br">NEW</span>}
              </div>

              <h3 className="job-title mt8">{j.title}</h3>
              <p className="job-co">{j.company}</p>

              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px', margin: '12px 0' }}>
                <span className="badge bdark"><MapPin size={10} /> {j.location}</span>
                <span className="badge bdark"><Briefcase size={10} /> {j.type}</span>
                <span className="badge bdark"><DollarSign size={10} /> {j.salary}</span>
              </div>

              <div style={{ display: 'flex', gap: '4px', marginBottom: '16px' }}>
                {j.skills?.map((s, i) => (
                  <span key={i} className="badge bc">{s}</span>
                ))}
              </div>

              <div style={{ display: 'flex', gap: '8px' }}>
                <a href={j.applyLink} target="_blank" rel="noreferrer" className="btn btn-primary btn-sm fw" style={{ textDecoration: 'none' }}>
                  <span>Apply Now</span>
                  <ExternalLink size={12} />
                </a>
                <button className="btn btn-ghost btn-sm">
                  <Heart size={14} />
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default Jobs;

import React, { useState, useEffect } from 'react';
import { problemService } from '../api/problemService';
import { Search, Filter, CheckCircle2, Circle, ChevronRight } from 'lucide-react';
import ProblemEditor from '../components/ProblemEditor';

const Problems = () => {
  const [problems, setProblems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState({ difficulty: '', topic: '' });
  const [selectedProblemId, setSelectedProblemId] = useState(null);

  useEffect(() => {
    fetchProblems();
  }, [filter]);

  const fetchProblems = async () => {
    setLoading(true);
    try {
      const data = await problemService.getAll(filter.difficulty, filter.topic);
      setProblems(data);
    } catch (err) {
      console.error('Failed to fetch problems', err);
    } finally {
      setLoading(false);
    }
  };

  if (selectedProblemId) {
    return (
      <ProblemEditor 
        problemId={selectedProblemId} 
        onBack={() => {
          setSelectedProblemId(null);
          fetchProblems();
        }} 
      />
    );
  }

  return (
    <div className="app-page on">
      <div className="section-hdr">
        <div>
          <h1 className="section-title">Problem Set</h1>
          <p className="section-sub">Master DSA with our curated collection of 425+ problems.</p>
        </div>
      </div>

      <div className="card mb24" style={{ padding: '12px' }}>
        <div style={{ display: 'flex', gap: '12px' }}>
          <div className="input-wrap" style={{ flex: 1 }}>
            <span className="input-ico"><Search size={14} /></span>
            <input type="text" placeholder="Search problems by name or ID..." style={{ paddingLeft: '38px' }} />
          </div>
          <div className="input-wrap" style={{ width: '150px' }}>
            <span className="input-ico"><Filter size={14} /></span>
            <select 
              style={{ paddingLeft: '38px' }}
              onChange={(e) => setFilter({ ...filter, difficulty: e.target.value })}
            >
              <option value="">Difficulty</option>
              <option value="Easy">Easy</option>
              <option value="Medium">Medium</option>
              <option value="Hard">Hard</option>
            </select>
          </div>
        </div>
      </div>

      <div className="card" style={{ padding: '0', overflow: 'hidden' }}>
        <div style={{ padding: '12px 16px', borderBottom: '1px solid var(--b1)', display: 'flex', fontSize: '11px', fontWeight: '700', color: 'var(--t3)' }}>
          <div style={{ width: '40px' }}>Status</div>
          <div style={{ flex: 1 }}>Title</div>
          <div style={{ width: '100px' }}>Difficulty</div>
          <div style={{ width: '120px' }}>Topics</div>
        </div>

        {loading ? (
          <div style={{ padding: '40px', textAlign: 'center', color: 'var(--t3)' }}>Loading problems...</div>
        ) : (
          problems.map((p) => (
            <div 
              key={p.id} 
              className="prob-row" 
              style={{ borderRadius: '0', border: 'none', borderBottom: '1px solid var(--b1)', marginBottom: '0' }}
              onClick={() => setSelectedProblemId(p.id)}
            >
              <div style={{ width: '40px' }}>
                {p.solved ? <CheckCircle2 size={16} style={{ color: 'var(--easy)' }} /> : <Circle size={16} style={{ color: 'var(--t4)' }} />}
              </div>
              <div style={{ flex: 1, display: 'flex', alignItems: 'center' }}>
                <span className="fw5 f13">{p.id}. {p.title}</span>
              </div>
              <div style={{ width: '100px' }}>
                <span className={`badge ${p.difficulty === 'Easy' ? 'bg' : p.difficulty === 'Medium' ? 'bm' : 'br'}`}>
                  {p.difficulty}
                </span>
              </div>
              <div style={{ width: '120px', display: 'flex', gap: '4px' }}>
                {p.topics?.slice(0, 1).map((t, i) => (
                  <span key={i} className="badge bdark">{t}</span>
                ))}
                {p.topics?.length > 1 && <span className="badge bdark">+{p.topics.length - 1}</span>}
              </div>
              <ChevronRight size={16} className="tc" />
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default Problems;
